// ── Breaking Ticker ──
function Ticker({ $ }) {
  const [x, sx] = useState(0); useEffect(() => { const i = setInterval(() => sx(p => p - 1.2), 25); return () => clearInterval(i); }, []);
  const s = brk.join("   ◆   ");
  return (
    <div style={{ background: $.pGrB, overflow: "hidden", whiteSpace: "nowrap", height: 36, display: "flex", alignItems: "center", userSelect: "none" }}>
      <div style={{ background: "#DB2777", padding: "0 16px", height: "100%", display: "flex", alignItems: "center", gap: 7, zIndex: 2, flexShrink: 0 }}>
        <span className="pls" />
        <span style={{ fontFamily: ff.d, fontSize: 11, color: "#fff", letterSpacing: 2.5, fontWeight: 500 }}>BREAKING</span>
      </div>
      <div style={{ display: "inline-flex", transform: `translateX(${x % 4000}px)`, fontFamily: ff.t, color: "#fff", fontSize: 13, fontWeight: 600, letterSpacing: 0.3 }}>
        <span style={{ paddingLeft: 20 }}>{s}</span>
        <span style={{ paddingLeft: 60 }}>{s}</span>
      </div>
    </div>
  );
}

// ── Navbar — Dark professional bar like TV9/NDTV ──
