// ── Section Heading ──
function SH({ t, s, $, a }) {
  return (
    <div style={{ marginBottom: 24 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        <div style={{ width: 4, height: 24, borderRadius: 2, background: a || $.p }} />
        <h2 style={{ fontFamily: ff.d, fontSize: 22, color: $.tx, letterSpacing: 1.5, textTransform: "uppercase" }}>{t}</h2>
      </div>
      {s && <p style={{ fontFamily: ff.b, fontSize: 13, color: $.t3, marginLeft: 16, marginTop: 3 }}>{s}</p>}
    </div>
  );
}

// ── Video Card ──
function VC({ v, $, onClick, lg }) {
  const cat = gc(v.c); return (
    <div
      onClick={onClick}
      style={{ background: $.card, borderRadius: 12, overflow: "hidden", cursor: "pointer", transition: "all .3s cubic-bezier(.4,0,.2,1)", border: `1px solid ${$.bdL}`, boxShadow: $.sh1 }}
      onMouseEnter={(e) => { e.currentTarget.style.boxShadow = $.shH; e.currentTarget.style.transform = "translateY(-3px)"; e.currentTarget.style.borderColor = $.p; }}
      onMouseLeave={(e) => { e.currentTarget.style.boxShadow = $.sh1; e.currentTarget.style.transform = ""; e.currentTarget.style.borderColor = $.bdL; }}
    >
      <div style={{ position: "relative", paddingTop: "56.25%", background: $._m === "dark" ? "#1a2236" : "#E2E8F0" }}>
        <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center" }}>
          <div style={{ width: 48, height: 48, borderRadius: "50%", background: `${$.p}DD`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, color: "#fff", boxShadow: `0 4px 12px ${$.p}44`, transition: "transform .2s" }}>▶</div>
        </div>
        <span style={{ position: "absolute", bottom: 6, right: 6, background: "rgba(0,0,0,.85)", color: "#fff", fontFamily: ff.m, fontSize: 10, padding: "2px 7px", borderRadius: 4 }}>{v.dur}</span>
        <span style={{ position: "absolute", top: 8, left: 8, background: cat.cl, color: "#fff", fontFamily: ff.h, fontSize: 9, fontWeight: 700, padding: "3px 9px", borderRadius: 4, textTransform: "uppercase", letterSpacing: 0.5 }}>{cat.nm}</span>
        {v.tr && <span style={{ position: "absolute", top: 8, right: 8, background: "rgba(220,38,38,.9)", color: "#fff", fontFamily: ff.h, fontSize: 8, fontWeight: 700, padding: "3px 7px", borderRadius: 4 }}>🔥 TRENDING</span>}
      </div>
      <div style={{ padding: lg ? "16px 18px 20px" : "12px 14px 16px" }}>
        <h3 style={{ fontFamily: ff.t, fontSize: lg ? 15 : 13, fontWeight: 700, color: $.tx, lineHeight: 1.5, marginBottom: 2, display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical", overflow: "hidden" }}>{v.ti}</h3>
        <p style={{ fontFamily: ff.b, fontSize: 11, color: $.t3, marginBottom: 8 }}>{v.en}</p>
        <div style={{ display: "flex", justifyContent: "space-between" }}>
          <span style={{ fontFamily: ff.b, fontSize: 11, color: $.t3 }}>
            👁
            {v.v}
          </span>
          <span style={{ fontFamily: ff.b, fontSize: 11, color: $.t3 }}>{v.d}</span>
        </div>
      </div>
    </div>
  );
}

