export default function App() {
  const [pg, sPg] = useState("home"); const [th, sTh] = useState("light"); const [mob, sMob] = useState(false); const [vd, sVD] = useState(null);
  const $ = palette[th]; const go = useCallback((p) => { sPg(p); window.scrollTo({ top: 0, behavior: "smooth" }); sMob(false); }, []);
  return (
    <div style={{ minHeight: "100vh", background: $.bg, transition: "background .3s" }}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700;800&family=IBM+Plex+Mono:wght@400;500&family=Nunito+Sans:wght@400;500;600;700&family=Oswald:wght@400;500;600;700&family=Noto+Sans+Telugu:wght@400;500;600;700&display=swap');*{margin:0;padding:0;box-sizing:border-box}body{background:${$.bg};transition:background .3s}::placeholder{color:${$.t3}!important}::-webkit-scrollbar{width:5px}::-webkit-scrollbar-track{background:transparent}::-webkit-scrollbar-thumb{background:${$.p}33;border-radius:3px}input:focus,textarea:focus{border-color:${$.p}!important;box-shadow:0 0 0 3px ${$.p}12!important}@keyframes pulse{0%,100%{opacity:1}50%{opacity:.25}}.pls{width:7px;height:7px;border-radius:50%;background:#EF4444;animation:pulse 1s infinite}.DN{display:flex!important}.MB{display:none!important}.MM{display:none!important}@media(max-width:900px){.DN{display:none!important}.MB{display:flex!important}.MM{display:flex!important}.HG,.CG,.AC,.MG,.CG2,.DG{grid-template-columns:1fr!important}.AG,.CG3,.FG2{grid-template-columns:1fr!important}.NF,.FG{flex-direction:column!important;grid-template-columns:1fr!important}}`}</style>
      <Nav pg={pg} go={go} $={$} tog={() => sTh(p => p === "light" ? "dark" : "light")} mob={mob} setMob={sMob} />
      {pg === "home" && <Home $={$} go={go} setVD={sVD} />}
      {pg === "videos" && <Videos $={$} vd={vd} setVD={sVD} />}
      {pg === "about" && <About $={$} />}
      {pg === "contact" && <Contact $={$} />}
      {pg === "admin" && <Admin $={$} />}
      <Foot $={$} go={go} />
    </div>
  );
}
